mapper.update:
update user
name = #{name}, gender = #{gender}, phone = #{phone}, pic = #{pic}, id_number = #{idNumber}, preference_completed = #{preferenceCompleted}, current_flight_id = #{currentFlightId}, cabin_type = #{cabinType},
where id = #{id}

mapper.select:
select u.id as userId, ifnull(u.name, concat('旅客', u.id)) as name, u.id_number as idNumber, u.phone as phone, case when u.gender = 1 then '男' when u.gender = 0 then '女' else '未知' end as gender, u.cabin_type as cabinType, case when u.cabin_type = 1 then '头等舱' when u.cabin_type = 2 then '商务舱' else '经济舱' end as cabinTypeLabel, case when exists( select 1 from user_preference up join user uu on uu.id = up.user_id where (u.id_number is not null and uu.id_number = u.id_number) or (u.id_number is null and up.user_id = u.id) ) then 1 else 0 end as preferenceCompleted, u.current_flight_id as currentFlightId from user u
and ( ifnull(u.name, '') like concat('%', #{keyword}, '%') or ifnull(u.id_number, '') like concat('%', #{keyword}, '%') or ifnull(u.phone, '') like concat('%', #{keyword}, '%') )
order by u.update_time desc, u.id desc limit #{limit}
